# API endpoint for training model
@app.route('/train', methods=['GET'])
def train():
    # Load CSV file and train model
    data = load_data('data.csv')
    model = train_model(data)

    # Save trained model to disk
    model.save('trained_model.h5')

    # Return success message
    return jsonify({'message': 'Model trained successfully!'})

# API endpoint for making predictions with the trained model
@app.route('/predict', methods=['POST'])
def predict():
    # Get image path from request body
    image_path = request.files['image'].read()

    # Load trained model from disk
    model = keras.models.load_model('trained_model.h5')

    # Make predictions with the trained model
    predictions = model.predict(image_path)

    # Return predictions as JSON object
